SELECT TOP 1 COUNT(*) AS TOTAL_TRANSACTIONS,
	SUM(PR.[AMOUNT]) AS MONTHLY_TOTAL,
	AVG(PR.[AMOUNT]) AS AVG_TRANSACTION 
FROM [PAYMENT_RECORDS] PR 
WHERE PR.[IsDeleted] = 0 
	AND PR.[PAYMENT_DATE] > DATEADD(DAY, -30,
	GETDATE()) 